SELECT instrument_name
FROM financial_instruments
WHERE market_value > (SELECT AVG(market_value) FROM financial_instruments);

SELECT portfolio_name
FROM portfolios
WHERE risk_level = 'Low';

SELECT AVG(market_value) AS average_market_value
FROM financial_instruments
WHERE industry = 'Financial leasing';

SELECT portfolio_name, creation_date, total_value
FROM portfolios
ORDER BY total_value DESC;

SELECT instrument_name, SUM(market_value) AS total_market_value, AVG(coupon_rate) AS average_coupon_rate
FROM financial_instruments
GROUP BY instrument_name;

SELECT SUM(total_value) AS total_portfolio_value
FROM portfolios
WHERE risk_level = 'High';

SELECT total_value 
FROM portfolios 
WHERE portfolio_id = 1;

SELECT SUM(market_value) AS total_market_value
FROM financial_instruments
WHERE industry = 'Financial leasing';

SELECT SUM(market_value) AS total_market_value
FROM financial_instruments
WHERE strftime('%Y', maturity_date) = strftime('%Y', 'now');

SELECT COUNT(*)
FROM financial_instruments
WHERE market_value > (SELECT AVG(market_value) FROM financial_instruments);

SELECT COUNT(*) AS total_transactions
FROM transaction_history
WHERE transaction_type = 'buy' AND transaction_date BETWEEN '2023-01-01' AND '2023-12-31';
